customCSS:
/* Solar Flare - Sun Energy */
@import url('https://fonts.googleapis.com/css2?family=Exo+2:wght@300;400;600;700&family=Open+Sans:wght@300;400;600&family=Source+Code+Pro&display=swap');

.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse 700px 500px at 50% 0%, rgba(255, 136, 0, 0.12), transparent),
    radial-gradient(ellipse 500px 400px at 30% 80%, rgba(255, 204, 0, 0.06), transparent);
}

.stat-card {
  border: 1px solid rgba(255, 170, 51, 0.15);
}

.stat-card::before {
  background: linear-gradient(90deg, #ffcc00, #ff8800, #ee4422);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(255, 136, 0, 0.3);
  box-shadow: 0 4px 25px rgba(255, 136, 0, 0.15);
}

.stat-value {
  text-shadow: 0 0 20px rgba(255, 170, 51, 0.5);
}

.celebration-title {
  background: linear-gradient(135deg, #ffcc00, #ff8800);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 20px rgba(255, 136, 0, 0.5));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(255, 170, 51, 0.1);
}

.miner-card:hover {
  border-color: rgba(255, 204, 0, 0.25);
}
